        benchmarks_subtitle: "Medido contra 12M+ de activos de alto rendimiento",
        neural_diagnostic: "Diagnóstico Neural",
        platform_compliance: "Cumplimiento de Plataforma",
        compliance_subtitle: "Auditoría según políticas de plataforma",
        toolkit: "Copy & CTA Creative Toolkit",
        toolkit_subtitle: "Arsenal de copies generado por IA para despliegue",
        action_plan: "Creative Action Plan",
        action_plan_subtitle: "Mejoras priorizadas y prompt de optimización",
        improvement_prompt: "AI IMPROVEMENT PROMPT:",
        tech_footer: "Tecnología Insitu AI",
        target_audience: "Público Objetivo",
        impact_score: "Score de Impacto",
        impact_score_subtitle: "Evaluación del éxito visual y potencial de conversión",
        impact_label: "IMPACTO",
