        clarity_project: "Proyecto de Claridad",
        engagement_potential: "Potencial de Engagement",
        strategic_diagnostic_summary: "Resumen de Diagnóstico Estratégico",
        strategic_diagnostic_default: "Diagnóstico estratégico completo para el activo visual.",
        focus_attention: "Enfoque / Atención",
        cognitive_load: "Carga Cognitiva",
        clarity_index: "Índice de Claridad",
        recall_potential: "Potencial de Recuerdo",
        creative_execution_default: "La ejecución creativa se alinea con los estándares de la plataforma.",
        high_attention: "Alta Atención (Crítico)",
        medium_attention: "Atención Media (Exploración)",
        low_attention: "Atención Baja (Periférica)",
        compliance_verdict: "Veredicto de Cumplimiento:",
        compliance_risk_moderate: "RIESGO MODERADO - REVISIÓN MANUAL RECOMENDADA",
