              doc.setFontSize(12); doc.setFont("helvetica", "bold"); setTextColor(COLORS.PRIMARY);
              doc.text("!", iconX, iconY + 4, { align: "center" });

              // Issue Label & Text
              doc.setFontSize(16); setTextColor(COLORS.PRIMARY);
